import{_ as t,c as o,a3 as i,o as a}from"./chunks/framework.BaPmp3PJ.js";const u=JSON.parse('{"title":"Overview","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"getting-started/overview.md","filePath":"getting-started/overview.md"}'),n={name:"getting-started/overview.md"};function r(s,e,l,c,d,h){return a(),o("div",null,e[0]||(e[0]=[i('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>The <strong>Workflow Description Language (WDL)</strong> (pronounced as <em>/hwɪdl/</em> or &quot;whittle&quot; with a &#39;d&#39;) is an open standard for describing data processing workflows using a human-readable/writeable syntax. It introduces a domain-specific language, as ratified in <a href="https://github.com/openwdl/wdl" target="_blank" rel="noreferrer">the openly developed specification</a>, that aims to provide simple but powerful facilities for (a) defining atomic units of computation (a <code>task</code>), (b) for connecting those atomic units together into a larger computation graph (a <code>workflow</code>), and (c) for effortlessly scaling the execution of these graphs in multiple environments.</p><p>We recommend you do a couple of things when starting out to have the best possible experience:</p><ul><li>Follow the quickstart guide to learn the most important concepts in WDL (<a href="./quickstart.html">link</a>).</li><li>Install an developer extension, such as <a href="https://marketplace.visualstudio.com/items?itemName=stjude-rust-labs.sprocket-vscode" target="_blank" rel="noreferrer">Sprocket</a> for Visual Studio Code, and follow the suggestions.</li><li>Pick an execution engine based on the environment you&#39;d like to run within and stick with it (<a href="./ecosystem.html#execution-engines">link</a>).</li><li>Join Slack to get help from the community (<a href="https://join.slack.com/t/openwdl/shared_invite/zt-ctmj4mhf-cFBNxIiZYs6SY9HgM9UAVw" target="_blank" rel="noreferrer">link</a>).</li></ul><p>The rest of this section is a guide to getting started with WDL—you can navigate through the guide and other sectiosn of the documentation with the buttons at the bottom or the left sidebar.</p><p>Happy workflowing 👋!</p>',6)]))}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
